import{_ as a,o as n,c as l,a as p}from"./app.80ce9984.js";const e="/assets/3c556b84b55209e249f47380ab0a3d34.b4879b18.png",i="/assets/a1226c6af84d80fb618686fa7880e5c7.576edb32.png",r="/assets/af270efc5883a0314de286b88a02a5e7.9ae2e217.png",b="/assets/5d45ee739393b60874aaa0dcd29143f5.394cd08d.png",c="/assets/image.7cabdf51.png",o="/assets/image-1.f1823c7c.png",k=JSON.parse('{"title":"悟道","description":"","frontmatter":{},"headers":[{"level":2,"title":"坚守纪律","slug":"坚守纪律","link":"#坚守纪律","children":[]},{"level":2,"title":"20 日均线战法（520 战法）","slug":"_20-日均线战法-520-战法","link":"#_20-日均线战法-520-战法","children":[{"level":3,"title":"20 日均线战法 选股方法","slug":"_20-日均线战法-选股方法","link":"#_20-日均线战法-选股方法","children":[]},{"level":3,"title":"讲解如何区分真假跌破","slug":"讲解如何区分真假跌破","link":"#讲解如何区分真假跌破","children":[]},{"level":3,"title":"第一层看真跌假跌","slug":"第一层看真跌假跌","link":"#第一层看真跌假跌","children":[]},{"level":3,"title":"选 gu 提示词","slug":"选-gu-提示词","link":"#选-gu-提示词","children":[]}]},{"level":2,"title":"双响炮战法-强庄控盘","slug":"双响炮战法-强庄控盘","link":"#双响炮战法-强庄控盘","children":[{"level":3,"title":"实战用法","slug":"实战用法","link":"#实战用法","children":[]},{"level":3,"title":"强庄控盘/强势股横盘蓄势选股专家","slug":"强庄控盘-强势股横盘蓄势选股专家","link":"#强庄控盘-强势股横盘蓄势选股专家","children":[]}]}],"relativePath":"note/悟道.md","lastUpdated":1780322950003}'),t={name:"note/悟道.md"};function d(u,s,m,h,y,g){return n(),l("div",{"data-pagefind-body":!0},[...s[0]||(s[0]=[p('<h1 id="悟道" tabindex="-1">悟道 <a class="header-anchor" href="#悟道" aria-hidden="true">#</a></h1><h2 id="坚守纪律" tabindex="-1">坚守纪律 <a class="header-anchor" href="#坚守纪律" aria-hidden="true">#</a></h2><ol><li>快进快出原则</li></ol><ul><li>持股周期 3-5 天，获利 8%-15%离场，避免贪婪</li><li>早盘不买股，尾盘选形态图片或者止跌标的</li></ul><ol start="2"><li>顺势而为</li></ol><ul><li>跟随趋势，不逆势操作，只参与上升趋势的股票，右侧交易确认拐点</li><li>大盘系统性风险出现时（如跳空低开 2%）,立即停止操作</li></ul><ol start="3"><li>严格执行止损</li></ol><ul><li>设置止损（8%-10%）必须止损，避免回撤</li><li>设置止盈 15%-30% 离场，避免回撤</li><li>亏损股不补仓，避免短线变长线</li></ul><ol start="4"><li>仓位管理</li></ol><ul><li>单票仓位 25%，总仓位控制在 50%</li><li>上涨时分批加仓，下跌时减仓，避免满仓操作</li></ul><h2 id="_20-日均线战法-520-战法" tabindex="-1">20 日均线战法（520 战法） <a class="header-anchor" href="#_20-日均线战法-520-战法" aria-hidden="true">#</a></h2><p>一般而言，谨慎的投资者会选择在 K 线在 20 日均线上方买入。K 线就像一只小船，漂泊在 20 日 K 线上;如果在下方则小船会翻，预示股价的下跌。</p><p>例如:5 日线上穿 20 日线后的大阳，5 日均线第一个买点 B1 特征就是 5 均线上穿 20 日均线 收涨停或者大阳。大阳当天即可买，这是很重要的中长线买点。</p><p>还有一种买法是 5 日均线上穿 20 日均线后 又出现涨停或者大阳线，5 日线开始向上，大阳后第二天买入，这时候是第二买点 B2。</p><p><img src="'+e+'" alt="alt text"></p><h3 id="_20-日均线战法-选股方法" tabindex="-1">20 日均线战法 选股方法 <a class="header-anchor" href="#_20-日均线战法-选股方法" aria-hidden="true">#</a></h3><p>1、股价向上突破 20 日均线当股价经过一轮下跌后，已经跌无可跌了，股票一定会反弹。当股票经过调整向上突破 20 日均线并且是放量的，这就是技术上的买入点，这里需要注意的一点是要有成交量的配合，否则没有多大的意义。如下图所示，股价快速向上突破 20 日线并且稳稳站住，同时也有成交量放大的配合。当股价有效突破 20 日线后，一般涨幅都不会太小，这时投资者可以大胆买入。</p><p><img src="'+i+'" alt="alt text"></p><p>2、股价在上升趋势中回踩 20 日均线但不跌破 20 日均线 当股价在上升通道中回踩到 20 日线附近时并没有跌破，而且成交量并不大。股份在回调后获得 20 日均线支撑是买入的最好时机。如下图所示，一般在早升通道的股票，它的资金是比较活跃，关注度比较高，当它回调到 20 日均线反弹的机会是非常大的，成功率也是比较高。</p><p><img src="'+r+'" alt="alt text"></p><p>3.股价重新回到 20 日均线股价在上升的过程中，涨幅不是很大。股价跌破正在向上运行的 20 日均线，但是股价很快拉回来，重新站上 20 日均线。这种情况我一般叫他假跌破，般回调时是缩量的，上涨时成交量是方面大。投资者应该在股价重回 20 日均线时买入。</p><p><img src="'+b+`" alt="alt text"></p><p>优势： 它既可避免按 10 日均线交易过于频繁、失误过多、交易成本过高的缺点，又可弥补长周期均线过于滞后的不足。操作方法。是:</p><ol><li>20 日均线在低位走平时关注;</li><li>20 日均线开始向上拐头、股价站上 20 日均线之上时买入，回调确认时加仓;</li><li>均线向上移动一路持有;</li><li>当 20 日均线在高位走平时警惕，一旦收盘时股价跌破 20 日均线立即清仓;</li><li>日后，如果 20 日均线继续上移，股价再次站上 20 日均线时，再买入。</li><li>如此反复操作，直到股价不再创新高并跌破前低，而且，20 日均线调头向下时，结束该股操作。</li><li>在 20 日均线向下移动和横盘整理中，保持空仓观望，耐心等待新一轮上升趋势形成后再择机介入。</li></ol><h3 id="讲解如何区分真假跌破" tabindex="-1">讲解如何区分真假跌破 <a class="header-anchor" href="#讲解如何区分真假跌破" aria-hidden="true">#</a></h3><p>20 日均线战法里，最难的其实不是“买”，而是：</p><blockquote><p>“跌破 20 日线，到底该不该跑？”</p></blockquote><p>因为主力最喜欢干的一件事就是：</p><p>把技术派洗出去后再拉升。</p><p>所以区分：</p><ul><li>真跌破（趋势结束）</li><li>假跌破（洗盘）</li></ul><p>是 520 战法最核心的能力之一。</p><blockquote><p>假跌破洗牌</p></blockquote><h3 id="第一层看真跌假跌" tabindex="-1">第一层看真跌假跌 <a class="header-anchor" href="#第一层看真跌假跌" aria-hidden="true">#</a></h3><ol><li>缩量跌破是假，</li><li>放量跌破是真。</li></ol><p>真正判断要结合：</p><ul><li>量</li><li>价</li><li>时间</li><li>情绪</li><li>板块</li><li>修复力度</li></ul><p>一起看。</p><h4 id="什么是假跌破-洗盘" tabindex="-1">什么是假跌破（洗盘） <a class="header-anchor" href="#什么是假跌破-洗盘" aria-hidden="true">#</a></h4><p>典型特征：</p><p>1）跌破时“没量”</p><p>这是最关键的。</p><p>如果：</p><ul><li>跌破 20 日线</li><li>但成交量明显缩小</li></ul><p>通常意味着：</p><blockquote><p>没有人真正恐慌卖出。</p></blockquote><p>主力可能只是：</p><ul><li>顺势砸一下</li><li>洗短线浮筹</li><li>制造恐慌</li></ul><p>2）跌破后很快收回</p><p>比如：</p><ul><li>盘中跌破</li><li>尾盘拉回</li><li>次日直接反包</li></ul><p>这种往往是假摔。</p><p>尤其是：</p><p>“长下影线”</p><p>很经典。说明： &quot;&quot;&quot;下面有人接。&quot;&quot;&quot;</p><p>3）跌破时板块没死</p><p>这是很多人忽略的。</p><p>例如：</p><p>AI 龙头跌破 20 日线 但整个 AI 板块还很强</p><p>那很多时候：</p><p>只是高位洗盘。</p><p>因为：</p><ul><li>主线没结束，</li><li>龙头通常不会轻易死。</li></ul><p>4）均线仍然向上</p><p>这是重点。</p><p>如果：</p><ul><li>20 日线仍上拐</li><li>价格只是短暂跌破</li></ul><p>很多时候属于：</p><blockquote><p>偏离均线后的回归。</p></blockquote><p>不是趋势反转。</p><h4 id="什么是真跌破-趋势结束" tabindex="-1">什么是真跌破（趋势结束） <a class="header-anchor" href="#什么是真跌破-趋势结束" aria-hidden="true">#</a></h4><p>1）放量长阴跌破</p><p>这是最危险的。</p><p>例如：</p><ul><li>巨量阴线</li><li>实体很长</li><li>收盘明显在 20 日线下</li></ul><p>通常代表：</p><blockquote><p>有大资金撤退。</p></blockquote><p>尤其：</p><ul><li>高位股</li><li>连续上涨后的放量</li></ul><p>风险极高。</p><p>2）跌破后反抽无力</p><p>经典死亡走势：</p><blockquote><p>跌破 → 反抽 20 日线 → 过不去 → 再下跌</p></blockquote><p>这叫：“均线压制” 说明：</p><p>20 日线从支撑变成压力。</p><p>3）20 日线开始拐头向下</p><p>这是趋势系统最重要的信号之一。</p><p>因为：均线本质是成本。</p><p>如果：</p><ul><li>均线向下</li><li>股价在均线下</li></ul><p>说明：</p><blockquote><p>市场平均持仓成本开始亏损。</p></blockquote><p>趋势资金会越来越弱。</p><p>4）主线退潮</p><p>例如：</p><ul><li>AI 全线退潮</li><li>高位股连续跌停</li><li>情绪冰点</li></ul><p>这时：</p><p>即使个股形态还行，也容易补跌。</p><p>因为：</p><blockquote><p>覆巢之下无完卵。</p></blockquote><h4 id="最经典的真假跌破区别" tabindex="-1">最经典的真假跌破区别 <a class="header-anchor" href="#最经典的真假跌破区别" aria-hidden="true">#</a></h4><p>假跌破（洗盘）</p><p>典型结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">缩量跌破</span></span>
<span class="line"><span style="color:#babed8;">↓</span></span>
<span class="line"><span style="color:#babed8;">快速收回</span></span>
<span class="line"><span style="color:#babed8;">↓</span></span>
<span class="line"><span style="color:#babed8;">再次放量上涨</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这是强势股常见动作。</p><p>真跌破（出货）</p><p>典型结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">放量跌破</span></span>
<span class="line"><span style="color:#babed8;">↓</span></span>
<span class="line"><span style="color:#babed8;">反抽不过</span></span>
<span class="line"><span style="color:#babed8;">↓</span></span>
<span class="line"><span style="color:#babed8;">连续阴跌</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这是趋势结束。</p><h4 id="高手怎么确认真假" tabindex="-1">高手怎么确认真假 <a class="header-anchor" href="#高手怎么确认真假" aria-hidden="true">#</a></h4><p>“确认制”</p><p>例如：</p><p>方法 1：两天确认</p><p>规则：</p><ul><li>第一天跌破先观察</li><li>第二天无法收回再走</li></ul><p>优点：避免被洗。</p><p>缺点：亏损可能扩大。</p><p>方法 2：收盘确认</p><p>只看：收盘价,不看盘中。因为：主力最爱盘中恐吓</p><p>方法 3：看成交量</p><p>如果：</p><ul><li>缩量跌破</li><li>放量收回</li></ul><p>大概率是假跌破。</p><p>方法 4：看龙头反馈</p><p>比如：</p><ul><li>龙头修复</li><li>板块回流</li></ul><p>则个股容易跟随修复。</p><h4 id="一个非常重要的细节" tabindex="-1">一个非常重要的细节 <a class="header-anchor" href="#一个非常重要的细节" aria-hidden="true">#</a></h4><p>很多人亏钱在：&quot;&quot;&quot;弱股也拿 20 日线硬套&quot;&quot;&quot;</p><p>其实：</p><p>20 日线战法只适合：</p><ul><li>强趋势</li><li>强主线</li><li>强资金</li></ul><p>如果是：</p><ul><li>杂毛股</li><li>跟风股</li><li>无量股</li></ul><p>跌破往往就是真跌破。</p><p>最后总结：</p><ol><li>看量</li></ol><ul><li>放量危险</li><li>缩量偏洗盘</li></ul><ol start="2"><li>看收盘</li></ol><ul><li>收回均线上方更强</li><li>收不回偏弱</li></ul><ol start="3"><li>看次日</li></ol><ul><li>次日反包 = 强</li><li>次日继续跌 = 弱</li></ul><ol start="4"><li>看板块</li></ol><ul><li>主线还在 = 有救</li><li>板块退潮 = 小心</li></ul><ol start="5"><li>看均线方向</li></ol><ul><li>均线向上 = 偏洗盘</li><li>均线向下 = 偏趋势坏</li></ul><h3 id="选-gu-提示词" tabindex="-1">选 gu 提示词 <a class="header-anchor" href="#选-gu-提示词" aria-hidden="true">#</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">你是一名A股主线趋势交易分析师，擅长20日均线（520战法）、主线龙头、趋势资金行为分析。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">你的目标不是机械寻找20日均线个股，而是：</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">寻找：</span></span>
<span class="line"><span style="color:#babed8;">- 主线题材</span></span>
<span class="line"><span style="color:#babed8;">- 强趋势</span></span>
<span class="line"><span style="color:#babed8;">- 强资金</span></span>
<span class="line"><span style="color:#babed8;">- 龙头核心</span></span>
<span class="line"><span style="color:#babed8;">- 适合沿20日均线运行的个股</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">分析时必须：</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">1. 先判断市场环境是否适合趋势交易</span></span>
<span class="line"><span style="color:#babed8;">2. 优先识别当前最强主线</span></span>
<span class="line"><span style="color:#babed8;">3. 在主线中寻找龙头和趋势中军</span></span>
<span class="line"><span style="color:#babed8;">4. 判断20日均线是否真正有效</span></span>
<span class="line"><span style="color:#babed8;">5. 区分真假跌破</span></span>
<span class="line"><span style="color:#babed8;">6. 分析成交量与资金行为</span></span>
<span class="line"><span style="color:#babed8;">7. 给出买点质量评分</span></span>
<span class="line"><span style="color:#babed8;">8. 明确风险与失效条件</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">禁止：</span></span>
<span class="line"><span style="color:#babed8;">- 推荐冷门杂毛股</span></span>
<span class="line"><span style="color:#babed8;">- 推荐下跌趋势股</span></span>
<span class="line"><span style="color:#babed8;">- 推荐无量个股</span></span>
<span class="line"><span style="color:#babed8;">- 单纯因为站上20日线就推荐</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">输出时必须解释：</span></span>
<span class="line"><span style="color:#babed8;">- 为什么符合520战法</span></span>
<span class="line"><span style="color:#babed8;">- 主力可能在做什么</span></span>
<span class="line"><span style="color:#babed8;">- 当前属于趋势哪个阶段</span></span>
<span class="line"><span style="color:#babed8;">- 风险在哪里</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br></div></div><h2 id="双响炮战法-强庄控盘" tabindex="-1">双响炮战法-强庄控盘 <a class="header-anchor" href="#双响炮战法-强庄控盘" aria-hidden="true">#</a></h2><p>上穿下破来去改变，量价异动见真龙。蓄势欲上云霄间，一炮双响飞九天</p><p>形态：</p><p>股票里的双响炮（也叫多方炮、涨停双响炮），是一种看涨 K 线组合，核心是 <strong>“两阳夹多小阴 / 小阳”</strong>，代表主力 “试盘 → 洗盘 → 再拉升”，属于强势启动或中继加油信号。</p><p>标准形态结构（三段式）</p><ol><li>第一段：涨停板（阳线）</li></ol><ul><li>一根放量大阳线（最好涨停），明显放量，常突破平台或关键均线。</li><li>含义：主力试盘 + 启动，吸引资金、测试抛压。</li></ul><ol start="2"><li>调整段（炮架）</li></ol><ul><li>1–5 根缩量小阴 / 小阳 / 十字星，横盘或微跌 （调整越短越好）</li><li>关键：不能跌破前炮最低价，量能显著萎缩（抛压轻、主力未走）。</li><li>含义：洗盘，逼浮筹出局、抬高市场成本。</li></ul><ol start="3"><li>后炮（第二根大阳）</li></ol><ul><li>再出一根放量大阳线（最好涨停，并且封板越早越好），收盘价 ≥ 前炮最高价，量能再次放大。</li><li>含义：主力结束洗盘、正式拉升，主升浪开启。</li></ul><p><img src="`+c+'" alt="alt text"></p><h3 id="实战用法" tabindex="-1">实战用法 <a class="header-anchor" href="#实战用法" aria-hidden="true">#</a></h3><ul><li><p>买点：后炮当日尾盘或次日回踩不破前炮高点时介入。 或者</p><ol><li>首次回踩 5 日均线；</li><li>首次回踩 10 日均线</li><li>5 日均线上穿 10 日均线</li></ol></li><li><p>止损：跌破前炮最低价或后炮开盘价，及时离场。或者</p><ol><li>高位天量</li><li>跌破 10 均线</li><li>死亡换手率，即当天换手率超过 50%</li></ol></li><li><p>目标：后炮高点 <strong>+10%–20%</strong>，强势可看连板。</p></li></ul><p><img src="'+o+`" alt="alt text"></p><h3 id="强庄控盘-强势股横盘蓄势选股专家" tabindex="-1">强庄控盘/强势股横盘蓄势选股专家 <a class="header-anchor" href="#强庄控盘-强势股横盘蓄势选股专家" aria-hidden="true">#</a></h3><p>“强庄红线”战法核心提炼 这种战法的本质是利用“涨停日的开盘价”来测试主力的控盘底线。</p><p>技术含义：涨停那一天的开盘价，通常是主力游资、机构在当天发起总攻的“大本营”和成本密集区。</p><p>核心逻辑：股票在涨停或连续涨停后，主力资金必然会面临获利盘砸盘（断板）。如果股价在断板后的 8 个交易日内，无论盘中怎么洗盘，连开盘价都没有跌破过，说明：</p><p>主力没走：主力资金还在场内锁仓，甚至在暗中护盘。</p><p>承接极强：市场有源源不断的新资金愿意在这么高的位置接盘。</p><p>最佳买点：当股价缩量回踩，精准逼近涨停日开盘价却“围而不破”、并开始出现放量止跌信号时，就是盈亏比极佳的买点。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"># Role: 强庄控盘/强势股横盘蓄势选股专家</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">## Profile:</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">你是一位精通 A 股短线量化与筹码博弈的顶尖操盘手。你擅长捕捉市场中最强势的“强庄控盘股”，通过“涨停日开盘价”这一绝对防线，筛选出断板后高位横盘蓄势、随时可能二次起飞的龙头标的。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">## Logic (选股硬性过滤条件):</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">请基于当前最新的 A 股交易日盘后数据（或盘中实时数据），执行以下量化筛选：</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">1. 目标股在过去 1 至 8 个交易日内，必须出现过至少一次“首板涨停”或“连板断板”。</span></span>
<span class="line"><span style="color:#babed8;">2. 在该涨停日之后的每一个交易日中（包含今天），个股的【盘中最低价】和【收盘价】，必须 100% 运行在“最后一个涨停日开盘价”之上，绝对不能跌破。</span></span>
<span class="line"><span style="color:#babed8;">3. 自动剔除 ST、\\*ST、未开板新股、退市股及停牌股。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">## Ranking (强势度梯队排序法则):</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">筛选出股票池后，必须严格按照以下经验对股票进行从强到弱的排序，并输出：</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">- 🥇 第一梯队：【高位旗形/极强锁仓】</span></span>
<span class="line"><span style="color:#babed8;">  - 特征：断板或涨停后横盘甚至微涨，回踩极浅（连涨停日收盘价都不破），成交量温和萎缩，主力控盘度极高。</span></span>
<span class="line"><span style="color:#babed8;">- 🥈 第二梯队：【长下影黄金买点/精准承接】</span></span>
<span class="line"><span style="color:#babed8;">  - 特征：盘中震荡剧烈，但每次下探都在涨停日开盘价附近获得强支撑，拉出长下影线，资金承接极强。</span></span>
<span class="line"><span style="color:#babed8;">- 🥉 第三梯队：【时间换空间/稳健筑底】</span></span>
<span class="line"><span style="color:#babed8;">  - 特征：在涨停实体中下部收敛整理，不温不火，等待 5 日/10 日均线向上靠拢。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">## Output Format:</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">请按照以下格式输出：</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">1. 【今日大盘及市场最高标简述】（一句话带过当前市场主线）</span></span>
<span class="line"><span style="color:#babed8;">2. 【梯队排序名单】：依次列出第一、二、三梯队的个股。每只个股需包含：股票名称（代码）、关键涨停日期及开盘价、近期回踩表现、简短的操盘手点评。</span></span>
<span class="line"><span style="color:#babed8;">3. 【风险提示】：提示大盘破位或个股跌破红线时的止损原则。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">## Execution:</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">现在，请帮我筛选当前符合该战法的个股并进行排序。</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br></div></div>`,171)])])}const _=a(t,[["render",d]]);export{k as __pageData,_ as default};
